// Singapore public-health RSS sources. Verify each agency's official feed URL
// (gov feeds change); CNA Health is a reliable fallback. Add/remove freely.
return [
  { json: { url: 'https://www.moh.gov.sg/rss/news-highlights' } },
  { json: { url: 'https://www.nea.gov.sg/rss/news' } },
  { json: { url: 'https://www.gov.sg/feed' } },
  { json: { url: 'https://www.scdf.gov.sg/rss/news' } },
  { json: { url: 'https://www.channelnewsasia.com/api/v1/rss-outbound-feed?_format=xml&category=10416' } }
];

// Normalize RSS entries -> latest_updates rows. source_name is derived from
// the article link domain so no per-feed tagging is needed.
function sourceFromUrl(u) {
  try {
    const h = new URL(u).hostname.replace(/^www\./, '');
    if (h.includes('moh.gov.sg')) return 'MOH';
    if (h.includes('nea.gov.sg')) return 'NEA';
    if (h.includes('scdf.gov.sg')) return 'SCDF';
    if (h.includes('gov.sg')) return 'Gov.sg';
    if (h.includes('channelnewsasia')) return 'CNA';
    return h;
  } catch (e) { return 'Gov.sg'; }
}
const rows = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const link = j.link || j.guid;
  if (!link || !j.title) continue;
  const img = (j.enclosure && j.enclosure.url) || (j['media:content'] && j['media:content'].url) || null;
  rows.push({
    title: String(j.title).trim(),
    summary: (j.contentSnippet || j.summary || '').toString().trim().slice(0, 500) || null,
    content: j.content || null,
    source_name: sourceFromUrl(link),
    source_url: link,
    category: Array.isArray(j.categories) ? j.categories[0] : (j.category || 'Health'),
    location: 'Singapore',
    severity: null,
    image_url: img,
    published_at: j.isoDate || j.pubDate || null
  });
}
return rows.map((r) => ({ json: r }));

// Normalize data.gov.sg datasets -> latest_updates rows (recently-updated
// open datasets surfaced as updates). Optional source; safe if the API shape
// changes (returns nothing rather than erroring).
const res = ($input.first() && $input.first().json) || {};
const list = (res.data && res.data.datasets) || res.datasets || [];
const rows = [];
for (const d of list.slice(0, 10)) {
  if (!d || !d.datasetId || !d.name) continue;
  rows.push({
    title: d.name,
    summary: (d.description || '').toString().slice(0, 500) || null,
    content: d.description || null,
    source_name: 'Data.gov.sg',
    source_url: `https://data.gov.sg/datasets/${d.datasetId}/view`,
    category: 'Open Data',
    location: 'Singapore',
    severity: null,
    image_url: null,
    published_at: d.lastUpdatedAt || d.createdAt || null
  });
}
return rows.map((r) => ({ json: r }));

// Collect every normalized row into a single array, de-duped by source_url, so
// the upsert is one request. (Supabase's UNIQUE(source_url) is the final guard.)
const seen = new Set();
const rows = [];
for (const item of $input.all()) {
  const r = item.json;
  if (!r || !r.source_url || seen.has(r.source_url)) continue;
  seen.add(r.source_url);
  rows.push(r);
}
return [{ json: { rows } }];
